import os
from sqlalchemy import create_engine

def db_connection():
    user = os.getenv('DB_USER') # get username from env variable (e.g., 'admin' in your case) 
    password = os.getenv('DB_PASSWORD')# Get Password From Environment Variable ('demo123' here as well, but you should use a secure way to handle this like using .env file or AWS Secrets Manager etc.)  
    host=os.getenv('HOST') # get Host from env variable (e.g., 'localhost:5432', in your case) 
    port = os.getenv('PORT')# Get Port From Environment Variable ('5432' here as well, but you should use a secure way to handle this like using .env file or AWS Secrets Manager etc.)  
    database_name=os.getenv('DBNAME') # get Database Name from env variable (e.g., 'hackathon_db', in your case) 
    
    connect_str = f"postgresql://{user}:{password}@{host}:{port}/{database_name}"  
      
    engine=create_engine(connect_str) # create the database connection using above parameters.     
        
    return engine# Returning Database Connection Engine